import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../../services/axios';

const CATEGORIES = ['Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Comedy', 'Theatre', 'Other'];

function CreateEvent() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    name: '', description: '', date: '', time: '',
    venue: '', category: 'Concert', totalSeats: '', price: '', image: ''
  });

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      await API.post('/events', { ...formData, totalSeats: parseInt(formData.totalSeats), price: parseFloat(formData.price) });
      alert('Event created! 🎉');
      navigate('/admin/manage-events');
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create event');
    } finally { setLoading(false); }
  };

  const inputStyle = {
    width: '100%', padding: '10px 14px', border: '2px solid #e5e7eb',
    borderRadius: '10px', fontSize: '0.85rem', outline: 'none',
    transition: 'border-color 0.2s', background: '#fafafa', boxSizing: 'border-box'
  };
  const labelStyle = { display: 'block', fontSize: '0.8rem', fontWeight: '700', color: '#374151', marginBottom: '6px' };

  return (
    <div style={{ padding: '2rem', background: '#f8f7ff', minHeight: '100vh' }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <Link to="/admin" style={{ color: '#7c3aed', textDecoration: 'none', fontSize: '0.85rem', fontWeight: '600' }}>← Back</Link>
        <h1 style={{ fontSize: '1.5rem', fontWeight: '800', color: '#1e1b4b', marginTop: '8px' }}>Create New Event</h1>
      </div>

      <div style={{ background: 'white', borderRadius: '16px', padding: '2rem', maxWidth: '700px', boxShadow: '0 2px 10px rgba(0,0,0,0.06)' }}>
        {error && <div style={{ background: '#fee2e2', color: '#991b1b', padding: '12px 16px', borderRadius: '10px', marginBottom: '1.5rem', fontSize: '0.85rem' }}>⚠️ {error}</div>}

        <form onSubmit={handleSubmit}>
          <div style={{ display: 'grid', gap: '1.2rem' }}>
            <div>
              <label style={labelStyle}>Event Name *</label>
              <input name="name" value={formData.name} onChange={handleChange} required style={inputStyle} placeholder="e.g. Music Festival 2026" />
            </div>
            <div>
              <label style={labelStyle}>Description *</label>
              <textarea name="description" value={formData.description} onChange={handleChange} required rows={3}
                style={{ ...inputStyle, resize: 'vertical' }} placeholder="Describe the event..." />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              <div>
                <label style={labelStyle}>Date *</label>
                <input type="date" name="date" value={formData.date} onChange={handleChange} required style={inputStyle} />
              </div>
              <div>
                <label style={labelStyle}>Time *</label>
                <input type="time" name="time" value={formData.time} onChange={handleChange} required style={inputStyle} />
              </div>
            </div>
            <div>
              <label style={labelStyle}>Venue *</label>
              <input name="venue" value={formData.venue} onChange={handleChange} required style={inputStyle} placeholder="e.g. Chennai Stadium" />
            </div>
            <div>
              <label style={labelStyle}>Category *</label>
              <select name="category" value={formData.category} onChange={handleChange} style={inputStyle}>
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              <div>
                <label style={labelStyle}>Total Seats *</label>
                <input type="number" name="totalSeats" value={formData.totalSeats} onChange={handleChange} required min="1" style={inputStyle} placeholder="500" />
              </div>
              <div>
                <label style={labelStyle}>Price (₹) *</label>
                <input type="number" name="price" value={formData.price} onChange={handleChange} required min="0" style={inputStyle} placeholder="999" />
              </div>
            </div>
            <div>
              <label style={labelStyle}>Image URL (Optional)</label>
              <input name="image" value={formData.image} onChange={handleChange} style={inputStyle} placeholder="https://..." />
            </div>
            <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
              <button type="submit" disabled={loading} style={{
                flex: 1, background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                color: 'white', border: 'none', padding: '12px', borderRadius: '10px',
                cursor: 'pointer', fontWeight: '700', fontSize: '0.9rem', opacity: loading ? 0.6 : 1
              }}>
                {loading ? '⏳ Creating...' : '✅ Create Event'}
              </button>
              <Link to="/admin" style={{
                flex: 1, background: '#f3f4f6', color: '#4b5563', padding: '12px',
                borderRadius: '10px', textDecoration: 'none', fontWeight: '600',
                textAlign: 'center', fontSize: '0.9rem'
              }}>Cancel</Link>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}
export default CreateEvent;
